/**
 * Purpose Section — Elixir/Digixr Canvas Animation
 *
 * Solid D → Logo D dissolve using pre-extracted pixel mask.
 * Concentric ripples expand from center, triggering seed blooms.
 * "Digital Elixir" brand text below the D.
 */
import { type Color, CYAN, TEAL, EMERALD, WHITE, rgba, lerpColor, isInView } from './utils';

// ── Pre-extracted logo D mask (120×120 grid, 1=filled 0=empty) ──
// Generated from image/logo/logo-dark-orig.png using mockups/tools/extract-mask.mjs
const MG = 120;
const MASK = '';

// Timing
const HOLD_SOLID = 2.0;
const DISSOLVE_DURATION = 8.0;
const DISSOLVE_START = HOLD_SOLID;

interface Particle {
  ox: number; oy: number; x: number; y: number;
  r: number; angle: number; vx: number; vy: number;
  color: Color; alpha: number; delay: number;
  released: boolean; phase: number;
}

interface Seed {
  x: number; y: number; distFromCenter: number;
  baseSize: number; baseAlpha: number; color: Color;
  bloom: number; bloomDecay: boolean;
  lastRippleId: number; phase: number;
}

interface Ripple {
  id: number; radius: number; alpha: number;
}

export function initElixirAnimation(canvas: HTMLCanvasElement): () => void {
  const ctx = canvas.getContext('2d');
  if (!ctx) return () => {};

  let W = 0, H = 0, animId = 0;
  let startTime: number | null = null;
  let cx = 0, cy = 0, dSize = 0, maxRadius = 0;
  let solidCanvas: HTMLCanvasElement;
  let solidCtx: CanvasRenderingContext2D;
  let logoCanvas: HTMLCanvasElement;
  let logoCtx: CanvasRenderingContext2D;
  let tempCanvas: HTMLCanvasElement;
  let tempCtx: CanvasRenderingContext2D;
  let particles: Particle[] = [];
  let dissolveProgress = 0;
  let seeds: Seed[] = [];
  let ripples: Ripple[] = [];
  let rippleId = 0;
  let frameCount = 0;

  // ── Render solid D with hollow center ──
  function renderSolidD(offCtx: CanvasRenderingContext2D, ox: number, oy: number, size: number) {
    const w = size * 0.88, h = size, thick = size * 0.22;
    const oL = ox - w * 0.38, oT = oy - h / 2, oB = oy + h / 2;

    const outer = new Path2D();
    outer.moveTo(oL, oT);
    outer.lineTo(ox + w * 0.12, oT);
    outer.bezierCurveTo(ox + w * 0.78, oT, ox + w * 0.78, oB, ox + w * 0.12, oB);
    outer.lineTo(oL, oB);
    outer.closePath();

    const inner = new Path2D();
    const iL = oL + thick, iT = oT + thick, iB = oB - thick;
    inner.moveTo(iL, iT);
    inner.lineTo(ox + w * 0.06, iT);
    inner.bezierCurveTo(ox + w * 0.56, iT, ox + w * 0.56, iB, ox + w * 0.06, iB);
    inner.lineTo(iL, iB);
    inner.closePath();

    const grad = offCtx.createLinearGradient(0, oT, 0, oB);
    grad.addColorStop(0, `rgb(${CYAN.r},${CYAN.g},${CYAN.b})`);
    grad.addColorStop(0.45, `rgb(${TEAL.r},${TEAL.g},${TEAL.b})`);
    grad.addColorStop(1, `rgb(${EMERALD.r},${EMERALD.g},${EMERALD.b})`);

    offCtx.fillStyle = grad;
    offCtx.fill(outer);
    offCtx.save();
    offCtx.globalCompositeOperation = 'destination-out';
    offCtx.fillStyle = '#000';
    offCtx.fill(inner);
    offCtx.restore();
  }

  // ── Render logo D from pre-computed mask ──
  function renderLogoD(offCtx: CanvasRenderingContext2D, ox: number, oy: number, size: number) {
    renderSolidD(offCtx, ox, oy, size);
    const w = size * 0.88, h = size;
    const oL = ox - w * 0.38, oT = oy - h / 2;
    const dBoundsW = w * 1.16, dBoundsH = h;

    offCtx.save();
    offCtx.globalCompositeOperation = 'destination-out';
    offCtx.fillStyle = '#000';
    const cellW = dBoundsW / MG, cellH = dBoundsH / MG;
    for (let gy = 0; gy < MG; gy++) {
      for (let gx = 0; gx < MG; gx++) {
        if (MASK[gy * MG + gx] === '0') {
          offCtx.fillRect(oL + gx * cellW, oT + gy * cellH, cellW + 0.5, cellH + 0.5);
        }
      }
    }
    offCtx.globalCompositeOperation = 'source-over';
    offCtx.restore();
  }

  // ── Compute dissolve particles from pixel diff ──
  function computeParticles() {
    particles = [];
    const dpr = window.devicePixelRatio || 1;
    const solidData = solidCtx.getImageData(0, 0, solidCanvas.width, solidCanvas.height);
    const logoData = logoCtx.getImageData(0, 0, logoCanvas.width, logoCanvas.height);
    const sw = solidCanvas.width;
    const particleR = Math.max(1.2, dSize * 0.006);
    const step = Math.max(2, Math.round(particleR * 2 * dpr));
    const solidTop = cy - dSize / 2;

    for (let py = 0; py < solidCanvas.height; py += step) {
      for (let px = 0; px < sw; px += step) {
        const idx = (py * sw + px) * 4;
        if (solidData.data[idx + 3] > 50 && logoData.data[idx + 3] <= 50) {
          const x = px / dpr, y = py / dpr;
          const vt = Math.max(0, Math.min(1, (y - solidTop) / dSize));
          const color = vt < 0.4 ? lerpColor(CYAN, TEAL, vt / 0.4)
                        : lerpColor(TEAL, EMERALD, (vt - 0.4) / 0.6);

          const dx = x - cx, dy = y - cy;
          const angle = Math.atan2(dy, dx);
          const distFromCenter = Math.sqrt(dx * dx + dy * dy);
          const maxDist = dSize * 0.5;
          const delay = Math.min(0.95, (distFromCenter / maxDist) * 0.6 + Math.random() * 0.3);

          particles.push({
            ox: x, oy: y, x, y,
            r: particleR * (0.6 + Math.random() * 0.8),
            angle, vx: 0, vy: 0,
            color, alpha: 0, delay,
            released: false,
            phase: Math.random() * Math.PI * 2,
          });
        }
      }
    }
  }

  // ── Seeds (blossom targets surrounding D) ──
  function generateSeeds() {
    seeds = [];
    const seedColors = [CYAN, TEAL, EMERALD];
    const count = Math.max(12, Math.min(20, Math.floor(W * H / 5000)));
    const cols = 5, rows = 4;
    const cellW = W / cols, cellH = H / rows;
    const cells: { c: number; r: number }[] = [];
    for (let r = 0; r < rows; r++)
      for (let c = 0; c < cols; c++)
        cells.push({ c, r });
    // Shuffle
    for (let i = cells.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [cells[i], cells[j]] = [cells[j], cells[i]];
    }
    const used = cells.slice(0, count);
    used.forEach((cell, i) => {
      const jX = (Math.random() - 0.5) * cellW * 0.7;
      const jY = (Math.random() - 0.5) * cellH * 0.7;
      const x = (cell.c + 0.5) * cellW + jX;
      const y = (cell.r + 0.5) * cellH + jY;
      const distFromCenter = Math.sqrt((x - cx) ** 2 + (y - cy) ** 2);
      seeds.push({
        x, y, distFromCenter,
        baseSize: 1.2 + Math.random() * 1.3,
        baseAlpha: 0.06 + Math.random() * 0.04,
        color: seedColors[i % 3],
        bloom: 0,
        bloomDecay: false,
        lastRippleId: -1,
        phase: Math.random() * Math.PI * 2,
      });
    });
  }

  // ── Setup ──
  function setup() {
    const dpr = window.devicePixelRatio || 1;
    const rect = canvas.parentElement!.getBoundingClientRect();
    W = rect.width;
    H = parseInt(getComputedStyle(canvas).height) || 440;
    canvas.width = W * dpr;
    canvas.height = H * dpr;
    canvas.style.width = W + 'px';
    canvas.style.height = H + 'px';
    ctx!.setTransform(dpr, 0, 0, dpr, 0, 0);

    cx = W * 0.5;
    cy = H * 0.38;
    dSize = Math.min(W * 0.4, H * 0.65);
    maxRadius = Math.sqrt(W * W + H * H) / 2 + 20;

    solidCanvas = document.createElement('canvas');
    solidCanvas.width = W * dpr;
    solidCanvas.height = H * dpr;
    solidCtx = solidCanvas.getContext('2d')!;
    solidCtx.setTransform(dpr, 0, 0, dpr, 0, 0);
    renderSolidD(solidCtx, cx, cy, dSize);

    logoCanvas = document.createElement('canvas');
    logoCanvas.width = W * dpr;
    logoCanvas.height = H * dpr;
    logoCtx = logoCanvas.getContext('2d')!;
    logoCtx.setTransform(dpr, 0, 0, dpr, 0, 0);
    renderLogoD(logoCtx, cx, cy, dSize);

    tempCanvas = document.createElement('canvas');
    tempCanvas.width = W * dpr;
    tempCanvas.height = H * dpr;
    tempCtx = tempCanvas.getContext('2d')!;

    computeParticles();
    generateSeeds();
    ripples = [];
    dissolveProgress = 0;
    startTime = null;
  }

  // ── Spawn concentric ripple from D center ──
  function spawnRipple() {
    rippleId++;
    ripples.push({ id: rippleId, radius: 0, alpha: 0.35 });
  }

  function getRippleColor(radius: number): Color {
    const pct = radius / maxRadius;
    if (pct < 0.3) return lerpColor(CYAN, TEAL, pct / 0.3);
    if (pct < 0.6) return lerpColor(TEAL, EMERALD, (pct - 0.3) / 0.3);
    return EMERALD;
  }

  // ── Update ──
  function update(elapsed: number, t: number) {
    if (elapsed >= DISSOLVE_START) {
      dissolveProgress = Math.min(1, (elapsed - DISSOLVE_START) / DISSOLVE_DURATION);
    }

    // Update dissolve particles
    for (const p of particles) {
      if (!p.released && dissolveProgress > p.delay) {
        p.released = true;
        p.alpha = 0.8;
        const speed = 0.2 + Math.random() * 0.6;
        p.vx = Math.cos(p.angle) * speed;
        p.vy = Math.sin(p.angle) * speed;
      }
      if (p.released) {
        p.vx += Math.sin(t * 0.8 + p.phase) * 0.005;
        p.vy += Math.cos(t * 0.6 + p.phase) * 0.004;
        p.vx *= 0.996;
        p.vy *= 0.996;
        p.x += p.vx;
        p.y += p.vy;
        const dist = Math.sqrt((p.x - p.ox) ** 2 + (p.y - p.oy) ** 2);
        p.alpha = Math.max(0, 0.8 - dist / (W * 0.35));
      }
    }

    // Concentric ripples — spawn every ~3s (180 frames)
    frameCount++;
    if (frameCount % 180 === 0) spawnRipple();

    // Update ripples
    for (let i = ripples.length - 1; i >= 0; i--) {
      const rip = ripples[i];
      const speed = Math.max(0.3, 0.6 - rip.radius * 0.0005);
      rip.radius += speed;
      rip.alpha = 0.35 * (1 - rip.radius / maxRadius);
      if (rip.radius > maxRadius || rip.alpha <= 0) {
        ripples.splice(i, 1);
        continue;
      }

      // Ripple passes a seed → trigger bloom
      for (const seed of seeds) {
        if (seed.lastRippleId === rip.id) continue;
        if (Math.abs(rip.radius - seed.distFromCenter) < 6) {
          seed.lastRippleId = rip.id;
          if (seed.bloom <= 0.05 && !seed.bloomDecay) {
            seed.bloom = 0.01;
          }
        }
      }
    }

    // Update seed blooms
    for (const s of seeds) {
      if (s.bloom > 0 && !s.bloomDecay) {
        s.bloom = Math.min(1, s.bloom + 0.015);
        if (s.bloom >= 1) s.bloomDecay = true;
      }
      if (s.bloomDecay) {
        s.bloom = Math.max(0, s.bloom - 0.008);
        if (s.bloom <= 0) s.bloomDecay = false;
      }
    }
  }

  // ── Draw: D shape ──
  function drawDShape() {
    if (dissolveProgress <= 0) {
      ctx!.drawImage(solidCanvas, 0, 0, solidCanvas.width, solidCanvas.height, 0, 0, W, H);
      return;
    }
    if (dissolveProgress >= 1) {
      ctx!.drawImage(logoCanvas, 0, 0, logoCanvas.width, logoCanvas.height, 0, 0, W, H);
      return;
    }
    const dpr = window.devicePixelRatio || 1;
    ctx!.drawImage(logoCanvas, 0, 0, logoCanvas.width, logoCanvas.height, 0, 0, W, H);
    tempCtx.setTransform(1, 0, 0, 1, 0, 0);
    tempCtx.clearRect(0, 0, tempCanvas.width, tempCanvas.height);
    tempCtx.drawImage(solidCanvas, 0, 0);
    tempCtx.globalCompositeOperation = 'destination-out';
    tempCtx.setTransform(dpr, 0, 0, dpr, 0, 0);
    for (const p of particles) {
      if (p.released) {
        tempCtx.beginPath();
        tempCtx.arc(p.ox, p.oy, p.r + 0.5, 0, Math.PI * 2);
        tempCtx.fill();
      }
    }
    tempCtx.globalCompositeOperation = 'source-over';
    ctx!.drawImage(tempCanvas, 0, 0, tempCanvas.width, tempCanvas.height, 0, 0, W, H);
  }

  // ── Draw: dissolve particles ──
  function drawParticles(t: number) {
    for (const p of particles) {
      if (!p.released || p.alpha <= 0.01) continue;
      const shimmer = 0.85 + 0.15 * Math.sin(t * 3 + p.phase);
      ctx!.beginPath();
      ctx!.arc(p.x, p.y, p.r * 2.5, 0, Math.PI * 2);
      ctx!.fillStyle = rgba(p.color, p.alpha * 0.07 * shimmer);
      ctx!.fill();
      ctx!.beginPath();
      ctx!.arc(p.x, p.y, p.r, 0, Math.PI * 2);
      ctx!.fillStyle = rgba(p.color, p.alpha * shimmer);
      ctx!.fill();
    }
  }

  // ── Draw: concentric ripples from center ──
  function drawRipples(t: number) {
    const pts = 48;
    for (const rip of ripples) {
      const color = getRippleColor(rip.radius);

      // Primary ring with organic distortion
      ctx!.beginPath();
      for (let j = 0; j <= pts; j++) {
        const theta = (j / pts) * Math.PI * 2;
        const distort = 2.5 * Math.sin(theta * 4 + t * 0.5) + 1.5 * Math.sin(theta * 6 - t * 0.8);
        const r = rip.radius + distort;
        const px = cx + Math.cos(theta) * r;
        const py = cy + Math.sin(theta) * r;
        if (j === 0) ctx!.moveTo(px, py); else ctx!.lineTo(px, py);
      }
      ctx!.closePath();
      ctx!.strokeStyle = rgba(color, rip.alpha);
      ctx!.lineWidth = 1.2;
      ctx!.stroke();

      // Secondary ring (depth)
      ctx!.beginPath();
      for (let j = 0; j <= pts; j++) {
        const theta = (j / pts) * Math.PI * 2;
        const distort = 2 * Math.sin(theta * 4 + t * 0.5 + 0.3) + 1.2 * Math.sin(theta * 6 - t * 0.8 + 0.5);
        const r = rip.radius + 4 + distort;
        const px = cx + Math.cos(theta) * r;
        const py = cy + Math.sin(theta) * r;
        if (j === 0) ctx!.moveTo(px, py); else ctx!.lineTo(px, py);
      }
      ctx!.closePath();
      ctx!.strokeStyle = rgba(color, rip.alpha * 0.3);
      ctx!.lineWidth = 0.8;
      ctx!.stroke();
    }
  }

  // ── Draw: seeds with bloom & fade ──
  function drawSeeds(t: number) {
    for (const s of seeds) {
      const bob = Math.sin(t * 0.7 + s.phase) * 1;
      const sx = s.x + Math.sin(t * 0.5 + s.phase) * 0.8;
      const sy = s.y + bob;
      const bt = s.bloom;

      if (bt > 0.01) {
        const eased = 1 - (1 - bt) * (1 - bt);
        const bloomSize = s.baseSize + 5 * eased;
        const bloomColor = lerpColor(s.color, WHITE, bt * 0.5);

        // Outer glow halo
        const haloR = Math.min(22, W * 0.045) * 1.5;
        const g1 = ctx!.createRadialGradient(sx, sy, 0, sx, sy, haloR);
        g1.addColorStop(0, rgba(s.color, 0.08 * bt));
        g1.addColorStop(1, 'transparent');
        ctx!.fillStyle = g1;
        ctx!.beginPath();
        ctx!.arc(sx, sy, haloR, 0, Math.PI * 2);
        ctx!.fill();

        // Inner burst (last 40% of bloom)
        if (bt > 0.6 && !s.bloomDecay) {
          const burstI = (bt - 0.6) / 0.4;
          const glowR = Math.min(22, W * 0.045);
          const g2 = ctx!.createRadialGradient(sx, sy, 0, sx, sy, glowR);
          g2.addColorStop(0, rgba(WHITE, 0.2 * burstI));
          g2.addColorStop(0.3, rgba(bloomColor, 0.25 * burstI));
          g2.addColorStop(1, 'transparent');
          ctx!.fillStyle = g2;
          ctx!.beginPath();
          ctx!.arc(sx, sy, glowR, 0, Math.PI * 2);
          ctx!.fill();
        }

        // Core dot
        ctx!.beginPath();
        ctx!.arc(sx, sy, bloomSize, 0, Math.PI * 2);
        ctx!.fillStyle = rgba(bloomColor, s.baseAlpha + (0.65 - s.baseAlpha) * bt);
        ctx!.fill();
      } else {
        // Dormant: small dim dot
        ctx!.beginPath();
        ctx!.arc(sx, sy, s.baseSize, 0, Math.PI * 2);
        ctx!.fillStyle = rgba(s.color, s.baseAlpha);
        ctx!.fill();
      }
    }
  }

  // ── Draw: brand text ──
  function drawBrandText() {
    const dBottom = cy + dSize / 2;
    const gap = dSize * 0.12;

    ctx!.save();
    ctx!.textAlign = 'center';
    ctx!.textBaseline = 'top';

    const mainSize = Math.max(18, Math.min(32, dSize * 0.13));
    ctx!.font = `italic 300 ${mainSize}px "Plus Jakarta Sans", sans-serif`;
    ctx!.letterSpacing = `${mainSize * 0.04}px`;
    const textY = dBottom + gap;
    const grad = ctx!.createLinearGradient(cx - mainSize * 3, textY, cx + mainSize * 3, textY + mainSize);
    grad.addColorStop(0, `rgb(${CYAN.r},${CYAN.g},${CYAN.b})`);
    grad.addColorStop(1, `rgb(${EMERALD.r},${EMERALD.g},${EMERALD.b})`);
    ctx!.fillStyle = grad;
    ctx!.fillText('Digital Elixir', cx, textY);
    ctx!.restore();
  }

  // ── Draw: background glow ──
  function drawGlow(t: number) {
    const breathe = 1 + 0.06 * Math.sin(t * 0.7);
    const r = dSize * 0.6 * breathe;
    const g = ctx!.createRadialGradient(cx, cy, 0, cx, cy, r);
    g.addColorStop(0, rgba(TEAL, 0.02));
    g.addColorStop(0.6, rgba(CYAN, 0.008));
    g.addColorStop(1, 'transparent');
    ctx!.fillStyle = g;
    ctx!.beginPath();
    ctx!.arc(cx, cy, r, 0, Math.PI * 2);
    ctx!.fill();
  }

  // ── Main loop ──
  function animate(time: number) {
    if (!isInView(canvas)) {
      animId = requestAnimationFrame(animate);
      return;
    }

    if (startTime === null) startTime = time;
    const elapsed = (time - startTime) * 0.001;
    const t = time * 0.001;

    ctx!.clearRect(0, 0, W, H);
    drawGlow(t);
    update(elapsed, t);
    drawSeeds(t);
    drawRipples(t);
    drawDShape();
    drawParticles(t);
    drawBrandText();

    animId = requestAnimationFrame(animate);
  }

  setup();
  spawnRipple();
  window.addEventListener('resize', setup);
  animId = requestAnimationFrame(animate);

  return () => {
    cancelAnimationFrame(animId);
    window.removeEventListener('resize', setup);
  };
}
